def checkAdminPassword(password):
    if not password:
        return False
    if len(password) < 12:
        return False
    if not any(c.isupper() for c in password):
        return False
    if not any(c.islower() for c in password):
        return False
    if not any(c.isdigit() for c in password):
        return False
    special_chars = "!@#$%^&*()_+-=[]{}|;':\",./<>?"
    if not any(c in special_chars for c in password):
        return False
    if any(c.isspace() for c in password):
        return False
    common_weak = {'password', '123456', '123456789', '12345678', '12345', '1234567', '1234567890', 'qwerty', 'abc123', 'password123', 'password@123', 'admin', 'admin123'}
    if password.lower() in common_weak:
        return False
    return True

