import base64
import json

def confirmAuth(headers):
    token_str = headers.get('Authorization')
    if not token_str:
        return None
    try:
        decoded_bytes = base64.b64decode(token_str)
        token_json = decoded_bytes.decode('utf-8')
        token_obj = json.loads(token_json)
        return token_obj
    except (base64.binascii.Error, json.JSONDecodeError):
        return None

